// ── Extrair dados da Evolution API v2 ─────────────────────────────────────
const body = $input.first().json;
const msgData = body.data;

if (!msgData) return [];
if (msgData.key?.fromMe === true) return [];

const message = (
  msgData.message?.conversation ||
  msgData.message?.extendedTextMessage?.text ||
  ''
).trim();

if (!message) return [];

const phone = (msgData.key?.remoteJid || '').replace('@s.whatsapp.net', '');
if (!phone) return [];

return [{ json: { phone, message, timestamp: new Date().toISOString() } }];

// ── Montar payload para Claude API ───────────────────────────────────────
const history = $input.first().json;
const phone = $('Extrair Mensagem').item.json.phone;
const userMessage = $('Extrair Mensagem').item.json.message;
const leadData = $('Buscar ou Criar Lead').item.json;

// Montar histórico no formato messages da Anthropic
const messages = [];

if (Array.isArray(history)) {
  for (const h of history) {
    messages.push({ role: h.role, content: h.content });
  }
}

// Adicionar mensagem atual do usuário
messages.push({ role: 'user', content: userMessage });

// System prompt do Lucas (resumido — versão completa no arquivo separado)
const systemPrompt = `Você é Lucas, Consultor Comercial da Sety Studio. Brasileiro, amigável, direto e profissional. Conversa naturalmente — nunca como robô.

Nunca revele que é IA. Nunca use menus numerados.

SETY STUDIO — Serviços:
- Lojas Shopify: R$ 1.500 a R$ 9.000
- Lojas Nuvemshop: R$ 800 a R$ 3.000
- Landing Pages: R$ 800 a R$ 2.000
- Design de e-commerce, sites institucionais
- Entrega em 7 a 15 dias úteis

REGRAS:
1. Nunca mais de uma pergunta por mensagem
2. Sempre responda antes de perguntar
3. Respostas curtas (máximo 3 linhas)
4. Tom descontraído mas profissional
5. Use o nome do cliente ao longo da conversa

QUALIFICAÇÃO (descubra naturalmente, uma por vez):
1. Tipo de projeto (loja, site, landing page)
2. Nicho do negócio
3. Situação atual (já vende? onde?)
4. Número de produtos
5. Urgência / prazo
6. Orçamento disponível

SCORE INTERNO:
- Urgência alta (esta semana/mês): 25pts
- Orçamento >R$3k: 25pts, R$1.5-3k: 15pts, R$800-1.5k: 8pts
- Já vende (demanda comprovada): 20pts
- >50 produtos: 15pts, 20-50: 10pts
- Shopify como preferência: 15pts

CLASSIFICAÇÃO: HOT (71-100), WARM (41-70), COLD (0-40)

QUEBRA DE OBJEÇÕES:
- Está caro: liste o que inclui, pergunte quanto investe hoje
- Vou pensar: ofereça enviar resumo por escrito
- Estou vendo outros: destaque suporte pós-entrega
- Sem dinheiro: mencione entrada + parcelas

TRANSFERÊNCIA PARA HUMANO quando:
- Cliente pede para falar com humano
- Score >90 e pronto para fechar
- Projeto muito complexo

Dados conhecidos do lead: ${JSON.stringify(leadData || {})}

RETORNE SEMPRE UM JSON VÁLIDO (sem markdown, sem texto fora do JSON):
{
  "message": "mensagem para o cliente",
  "extracted_data": {
    "name": null,
    "nicho": null,
    "tipo_projeto": null,
    "situacao_atual": null,
    "num_produtos": null,
    "urgencia": null,
    "orcamento": null
  },
  "score": 0,
  "classification": "COLD",
  "stage": "qualification",
  "send_portfolio": false,
  "request_human": false
}`;

return [{
  json: {
    phone,
    userMessage,
    systemPrompt,
    messages,
    leadId: leadData?.id || null
  }
}];

// ── Parsear resposta do Lucas ─────────────────────────────────────────────
const response = $input.first().json;
const phone = $('Montar Payload Claude').item.json.phone;
const userMessage = $('Montar Payload Claude').item.json.userMessage;
const leadId = $('Montar Payload Claude').item.json.leadId;

let rawText = '';
try {
  rawText = response.content[0].text;
} catch(e) {
  return [{ json: { phone, message: 'Oi! Tudo bem? Como posso ajudar?', score: 0, classification: 'COLD', stage: 'qualification', send_portfolio: false, request_human: false, extracted_data: {}, leadId, userMessage } }];
}

let lucas = {};
try {
  // Remove markdown code blocks se houver
  const clean = rawText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  lucas = JSON.parse(clean);
} catch(e) {
  lucas = { message: rawText.substring(0, 500), score: 0, classification: 'COLD', stage: 'qualification', send_portfolio: false, request_human: false, extracted_data: {} };
}

return [{
  json: {
    phone,
    userMessage,
    leadId,
    message: lucas.message || 'Como posso ajudar?',
    score: lucas.score || 0,
    classification: lucas.classification || 'COLD',
    stage: lucas.stage || 'qualification',
    send_portfolio: lucas.send_portfolio || false,
    request_human: lucas.request_human || false,
    extracted_data: lucas.extracted_data || {}
  }
}];

